var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"KNIGHT_REPLACER_REGEN_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_REGEN_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L3_1","type":"dialog","speaker":"KNIGHT_REPLACER_REGEN_NULL","text":{"KOREA":"......왔군.","JPN":"……来たな。","ENG":"You're here.","TWN":"……來了。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"KNIGHT_REPLACER_REGEN_NULL","text":{"KOREA":"너희들의 상대는 나다.","JPN":"貴様らの相手は、この私だ。","ENG":"I'll be dealing with you.","TWN":"你們的對手是我。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"......리플레이서 나이트.","JPN":"……リプレイサー・ナイト。","ENG":"Replacer Knight.","TWN":"……克隆．騎士。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"하지만 혼자서 나오다니, 아무리 그래도 우릴 너무 무시하는 거 아냐?","JPN":"いくらなんでも一人で来るなんて、アタシたちを見くびるにもほどがあるわね。","ENG":"You're out here alone? This is almost insulting.","TWN":"但妳竟然敢一個人出來，不管怎麼樣，這也太不把我們放在眼裡了吧？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"지난번에는 한 방 먹었지만, 이번엔 그렇게 호락호락하지 않을걸?","JPN":"前回は一杯食わされたけど、今回はそう簡単にはいかないわよ？","ENG":"You got me good last time, but it won't be so easy this time around.","TWN":"上次我們雖然被擺了一道，但這次我們可不會這麼好欺負了。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"KNIGHT_REPLACER_REGEN_NULL","text":{"KOREA":"바보 같은 소릴 하는군.","JPN":"バカなことを言うな。","ENG":"You're being absurd.","TWN":"說什麼蠢話。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"KNIGHT_REPLACER_REGEN_NULL","text":{"KOREA":"한때나마 <color=#ffd34c>왕</color>의 동료였던 자들을 상대로 여유부릴 생각은 없다.","JPN":"一時ではあるが、<color=#ffd34c>王</color>の仲間だった者を相手に、余裕ではいられない。","ENG":"I have no intention of taking you lightly. You were once colleagues of <color=#ffd34c>King</color>.","TWN":"對付<color=#ffd34c>王</color>曾經的同伴，我可不覺得自己會有什麼餘裕。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"KNIGHT_REPLACER_REGEN_NULL","text":{"KOREA":"다만 테라사이드 시스템의 수호자로서 내 의무에 충실할 뿐이다.","JPN":"私は、テラサイドシステムの守護者としての義務を果たすだけだ。","ENG":"I'm just sticking to my duty as the guardian of System Terraside.","TWN":"作為特拉賽德系統的守護者，我只是恪守我的任務而已。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"주의하십시오, 중장님.","JPN":"お気を付けください、中将。","ENG":"Be careful, Lieutenant General.","TWN":"請您小心，中將大人。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"저 자가 바로 KS-1 도시관리국의 배신 사건을 주도한 장본인입니다.","JPN":"あの者こそが、KS-1都市管理局の事件を主導した張本人です。","ENG":"That's the mastermind behind the betrayals of KS-1 City Management.","TWN":"她就是主導KS-1城市管理局叛亂事件的本人。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"나도 보고는 받았네, 카일.","JPN":"私も報告は受けているよ、カイル。","ENG":"So I've been told, Kyle.","TWN":"我收到報告了，凱爾。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"하지만 보고서 내용에 있던 것과는 조금 다르군.","JPN":"だが、報告書の内容とは少しズレがあるな。","ENG":"But she seems a little bit different than how she was described in the reports.","TWN":"但和報告裡的內容有點不一樣啊。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"보고서에는 훨씬 더 공격적인 성격이라고 나와 있던 것 같은데?","JPN":"報告書には、あれよりも遥かに攻撃的な性格だと書かれていたような気がするが？","ENG":"I thought she'd be much more aggressive than this.","TWN":"報告裡好像說她具有更強烈的攻擊性格？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"관리국에서 제공한 정보에 따르면 저 자는 이전의 <color=#ffd34c>리플레이서 나이트</color>를 기반으로 하여 새롭게 만들어진 <color=#ffd34c>진화 재생체</color>라고 합니다.","JPN":"管理局提供の情報によると、あの者は以前の<color=#ffd34c>リプレイサー・ナイト</color>を\\nもとに新しく作られた<color=#ffd34c>進化再生体</color>だそうです。","ENG":"According to the intel from the Administration, she's a <color=#ffd34c>Regenerated Replacer</color> newly built from the bioinformation of the <color=#ffd34c>Replacer Knight</color>.","TWN":"根據管理局提供的情報，那個人是以過去的<color=#ffd34c>克隆．騎士</color>為基礎，被重新創造出來的 <color=#ffd34c>進化再生體</color>。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"성격은 물론 전투 능력도 이전과는 비교할 수 없을 정도로 상승했을 것으로 추정됩니다.","JPN":"性格の変化はもちろん、戦闘能力も以前とは比べ物にならないほど上昇しているとみられます。","ENG":"We're assuming that her personality has gone through considerable changes, just like her combat abilities have.","TWN":"不只是性格，推測她連戰鬥能力都上升到了以前無法比擬的程度。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"......흥미롭군.","JPN":"……興味深いな。","ENG":"Interesting.","TWN":"……真有趣呢。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"관리국 최고관리위원회는 대체 어떻게 그런 정보를 다 알고 있는 걸까?","JPN":"管理局の最高管理委員会は、いったいどうやってその手の情報を入手したのだろうな？","ENG":"How does the Administration High Committee know all this?","TWN":"管理局最高管理委員會到底是怎麼知道這些事情的啊？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"......아마도 지난번 저희와 합동작전을 진행했던 코핀 컴퍼니의 정보를 토대로 분석한 것이 아닐까요?","JPN":"……前回、我々と合同作戦を行ったコフィンカンパニーの情報をもとに、\\n分析しているのではないでしょうか。","ENG":"Perhaps they analyzed the details of our last joint operation with the Coffin Company.","TWN":"……大概是以上次和我們聯合作戰的科芬公司的情報為基礎，分析出來的吧？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"리플레이서 나이트와 단독교전을 하고도 살아남은 태스크포스는 그곳이 유일하니까요.","JPN":"リプレイサー・ナイトと単独で交戦して生き残ったタスクフォースは、そこが唯一ですからね。","ENG":"They're the only TASKFORCE team that survived a head-on battle against the Replacer Knight.","TWN":"因為和克隆．騎士單獨戰鬥後還活下來的特遣勢力，就只有他們了。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그래, 그럴 수도 있겠지.","JPN":"そうか、そうかもしれんな。","ENG":"You may be right.","TWN":"沒錯，這也很有可能。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"어쨌든 저 녀석을 박살내면 되는 거지? 카일.","JPN":"とにかく、あいつをぶっ潰せばいいんだな？　カイル。","ENG":"Anyway, all we have to is knock that thing down. Right, Kyle?","TWN":"總之，打爆那傢伙就可以了吧？凱爾。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"최근에 계속 잔머리 굴리는 녀석들만 상대하느라 피곤했는데, 이번엔 좀 달랐으면 좋겠어.","JPN":"最近、小賢しい奴らばっかり相手していて疲れてるんだ。今回は違うと良いんだが。","ENG":"I was growing tired of dealing with people trying to pull a stunt. I wish she'd be different.","TWN":"最近一直在和一些耍小聰明的傢伙戰鬥，我已經感到厭煩了，希望這次能有點不一樣。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"아직 다른 리플레이서 간부들의 위치가 파악되지 않았습니다, 대령님.","JPN":"まだ他のリプレイサー幹部らの位置が把握できていません、大佐。","ENG":"We have yet to locate the rest of the Replacer officers, Colonel.","TWN":"我們目前還沒有掌握其他克隆集團幹部的位置，上將。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"어쩌면 우리가 빈틈을 보이는 순간 습격해 올지도 모릅니다.","JPN":"ひょっとすると、我々が隙を見せた瞬間、奇襲をかけてくるかもしれません。","ENG":"They may pounce on us the moment we let our guard down.","TWN":"大概是想要趁我們露出破綻的瞬間發動襲擊吧。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"이럴 때일수록 신중하게......","JPN":"こういう時ほど慎重に……","ENG":"I insist that we take careful appro—","TWN":"越是這種時候，越是要慎重……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"아아, 머리 쓰는 게 네 장점이긴 하지만 말이야, 카일......","JPN":"はあ、頭を使うのがお前の良いところではあるけどな、カイル……","ENG":"Look, Kyle. I know you're smart and all,","TWN":"啊啊，用腦子的事情是你的長處，凱爾……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"부딪칠 때는 확실히 부딪쳐 봐야 알 수 있는 것도 있는 법이라고.","JPN":"実際ぶつかってみないとわからない時だって、あるんだぜ？","ENG":"but some things never become clear until you charge into them.","TWN":"但槓上的時候，就只有確實打一架才會知道。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"어휴...... 누가 근육바보 아니랄까 봐......","JPN":"ふう……ほんと筋肉バカね……","ENG":"Geez, could you sound any more like a musclebrain?","TWN":"唉……誰不知道你是個肌肉笨蛋……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"......대령님에 대한 평가만큼은 실비아 씨와 의견이 일치하는 것 같군요.","JPN":"……大佐への評価だけは、シルビアさんと一致しているみたいですね。","ENG":"It seems Sylvia and I have a shared opinion about you, Colonel.","TWN":"……看來只有在對上將的評價上，我跟希爾維亞小姐的意見一致。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"리플레이서 나이트라고 했지?","JPN":"リプレイサー・ナイトって言ったよな？","ENG":"Replacer Knight, was it?","TWN":"妳是叫克隆．騎士吧？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"KNIGHT_REPLACER_REGEN_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"이렇게 나선 걸 보면 실력에 꽤 자신이 있는 것 같은데......","JPN":"こうやって前線に出てるってことは、腕にはかなり自信があるようだが……","ENG":"You're here on your own, and I take it as a sign of confidence.","TWN":"看妳這個樣子，似乎是對自己的實力很有自信……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"나도 일단은 관리국 비공인 <color=#ffd34c>탑 카운터</color>라서 말이야.","JPN":"俺も一応は管理局非公認の<color=#ffd34c>トップカウンター</color>なんでね。","ENG":"But you see, I'm the Administration's <color=#ffd34c>top Counter</color>, although unofficially.","TWN":"但我可是管理局非公認的 <color=#ffd34c>最強制裁者</color>。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"그러니까 처음부터 전력을 다하길 바래. 실망하고 싶진 않거든.","JPN":"最初から全力でかかってこい。がっかりしたくないんだ。","ENG":"I really think you should go all-out from the very beginning. I'd hate to be disappointed.","TWN":"所以希望妳一開始就使出全力。我可不想失望。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KNIGHT_REPLACER_REGEN_NULL","text":{"KOREA":"......상대로서 부족함은 없군.","JPN":"……相手にとって不足はないか。","ENG":"You look like a worthy opponent.","TWN":"……作為我的對手沒有什麼不足之處呢。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_REGEN_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"KNIGHT_REPLACER_REGEN_NULL","text":{"KOREA":"나 역시 이런 싸움을 고대해왔다.","JPN":"私としても、こんな対決を心待ちにしてきた。","ENG":"I've been waiting for a fight like this.","TWN":"我也期待這樣的戰鬥很久了。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"KNIGHT_REPLACER_REGEN_NULL","text":{"KOREA":"덤벼라!","JPN":"かかってこい！","ENG":"Bring it on!","TWN":"放馬過來吧！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_BOSS_KNIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_REGEN_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};